import React, { useState } from 'react';

let counter = 100;
const uid = () => String(++counter);

const INITIAL = [
  {
    id: '1',
    text: 'This is the first comment.',
    replies: [
      { id: '2', text: 'A reply to the first.', replies: [] },
    ],
  },
  { id: '3', text: 'A second top-level comment.', replies: [] },
];

function addReply(nodes, parentId, text) {
  return nodes.map((n) =>
    n.id === parentId
      ? { ...n, replies: [...n.replies, { id: uid(), text, replies: [] }] }
      : { ...n, replies: addReply(n.replies, parentId, text) }
  );
}

function Comment({ node, openId, setOpenId, onReply }) {
  const [draft, setDraft] = useState('');
  const open = openId === node.id;

  return (
    <div style={{ marginLeft: 16, borderLeft: '2px solid #eee', paddingLeft: 12, marginTop: 8 }}>
      <p style={{ margin: '4px 0' }}>{node.text}</p>
      <button onClick={() => setOpenId(open ? null : node.id)} style={{ fontSize: 12, cursor: 'pointer', border: 'none', background: 'none', color: '#2563eb' }}>
        {open ? 'Cancel' : 'Reply'}
      </button>
      {open && (
        <div style={{ display: 'flex', gap: 6, marginTop: 6 }}>
          <input value={draft} onChange={(e) => setDraft(e.target.value)} placeholder="Write a reply…" style={{ flex: 1, padding: 6 }} />
          <button
            onClick={() => {
              const v = draft.trim();
              if (v) onReply(node.id, v);
            }}
            style={{ cursor: 'pointer' }}
          >
            Post
          </button>
        </div>
      )}
      {node.replies.map((r) => (
        <Comment key={r.id} node={r} openId={openId} setOpenId={setOpenId} onReply={onReply} />
      ))}
    </div>
  );
}

export default function NestedComments() {
  const [tree, setTree] = useState(INITIAL);
  const [openId, setOpenId] = useState(null);

  const onReply = (parentId, text) => {
    setTree((t) => addReply(t, parentId, text));
    setOpenId(null);
  };

  return (
    <div style={{ maxWidth: 480 }}>
      {tree.map((n) => (
        <Comment key={n.id} node={n} openId={openId} setOpenId={setOpenId} onReply={onReply} />
      ))}
    </div>
  );
}

