import { Component, Input, Output, EventEmitter } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

interface CommentNode { id: string; text: string; replies: CommentNode[]; }

let counter = 100;
const uid = () => String(++counter);

@Component({
  selector: 'app-comment',
  template: `
    <div style="margin-left: 16px; border-left: 2px solid #eee; padding-left: 12px; margin-top: 8px;">
      <p style="margin: 4px 0;">{{ node.text }}</p>
      <button (click)="open = !open" style="font-size: 12px; cursor: pointer; border: none; background: none; color: #2563eb;">{{ open ? 'Cancel' : 'Reply' }}</button>
      <div *ngIf="open" style="display: flex; gap: 6px; margin-top: 6px;">
        <input [value]="draft" (input)="draft = $any($event.target).value" placeholder="Write a reply…" style="flex: 1; padding: 6px;" />
        <button (click)="post()" style="cursor: pointer;">Post</button>
      </div>
      <app-comment *ngFor="let r of node.replies" [node]="r" (reply)="reply.emit($event)"></app-comment>
    </div>
  `,
})
export class CommentComponent {
  @Input() node!: CommentNode;
  @Output() reply = new EventEmitter<{ parentId: string; text: string }>();
  open = false;
  draft = '';

  post(): void {
    const v = this.draft.trim();
    if (!v) {
      return;
    }
    this.reply.emit({ parentId: this.node.id, text: v });
    this.draft = '';
    this.open = false;
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Nested Comments Demo</h1>
      <div style="max-width: 480px;">
        <app-comment *ngFor="let n of tree" [node]="n" (reply)="onReply($event)"></app-comment>
      </div>
    </div>
  `,
})
export class AppComponent {
  tree: CommentNode[] = [
    {
      id: '1',
      text: 'This is the first comment.',
      replies: [{ id: '2', text: 'A reply to the first.', replies: [] }],
    },
    { id: '3', text: 'A second top-level comment.', replies: [] },
  ];

  onReply(e: { parentId: string; text: string }): void {
    this.addReply(this.tree, e.parentId, e.text);
  }

  addReply(nodes: CommentNode[], parentId: string, text: string): boolean {
    for (const n of nodes) {
      if (n.id === parentId) {
        n.replies.push({ id: uid(), text, replies: [] });
        return true;
      }
      if (this.addReply(n.replies, parentId, text)) {
        return true;
      }
    }
    return false;
  }
}

@NgModule({
  declarations: [AppComponent, CommentComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
